import { Box, ToggleButton, ToggleButtonGroup, Typography } from '@mui/material';
import React from 'react';
import { useNavigate } from 'react-router-dom';
import { getName } from './texts';

const Filter = (props) => {
    const { alignment, setAlignment, setProducts, products, categories = [] } = props;
    const navigate = useNavigate();

    const handleAlignment = (event, newAlignment) => {
        if (!newAlignment) {
            navigate('/');
            setProducts(products);
            setAlignment(newAlignment);
            return;
        }
        setAlignment(newAlignment);
        navigate('/' + (newAlignment ? newAlignment + '/page1' : ''));
        setProducts(products.filter((good) => good.category.includes(newAlignment)));
    };

    return (
        <Box sx={{ overflowX: 'auto', pb: 1, mb: 4, '&::-webkit-scrollbar': { display: 'none' } }}>
            <ToggleButtonGroup
                value={alignment}
                exclusive
                onChange={handleAlignment}
                sx={{
                    display: 'flex',
                    gap: 1.5,
                    border: 'none',
                    '& .MuiToggleButtonGroup-grouped': {
                        border: '1px solid rgba(255, 255, 255, 0.1)',
                        borderRadius: '12px !important',
                        px: 3,
                        py: 1,
                        color: 'text.secondary',
                        textTransform: 'none',
                        transition: 'all 0.2s ease',
                        '&.Mui-selected': {
                            backgroundColor: 'primary.main',
                            color: 'black',
                            borderColor: 'primary.main',
                            fontWeight: 700,
                            '&:hover': {
                                backgroundColor: 'primary.main',
                                opacity: 0.9
                            }
                        },
                        '&:hover': {
                            borderColor: 'primary.main',
                            color: 'primary.main',
                            backgroundColor: 'transparent'
                        }
                    }
                }}
            >
                <ToggleButton value="">
                    All Items
                </ToggleButton>
                {categories.map((cat) => (
                    <ToggleButton key={cat} value={cat}>
                        <Typography variant="body2" sx={{ fontWeight: 'inherit' }}>
                            {getName(cat)}
                        </Typography>
                    </ToggleButton>
                ))}
            </ToggleButtonGroup>
        </Box>
    );
}

export default Filter;
